    41→    const allTasks = tasks;
    42→    const columnTasks = allTasks.filter((t) => t.status === selectedColumn);
    43→    const filteredAll = includeArchived
    44→      ? allTasks
    45→      : allTasks.filter((t) => !t.archivedAt);
    46→    const filteredColumn = includeArchived
    47→      ? columnTasks
    48→      : columnTasks.filter((t) => !t.archivedAt);
    49→
    50→    return {
    51→      single: 0, // Not implemented in this modal
