import { useState, useEffect } from 'react';
import { X, AlertTriangle } from 'lucide-react';
import { useCalendarStore } from '../stores/useCalendarStore';
import { REMINDER_OPTIONS } from '../services/eventReminders';
import { detectConflicts, formatConflictMessage, getConflictDetails } from '../utils/conflictDetection';
import type { CalendarEvent } from '../types';

interface EventCreateModalProps {
  dateKey: string;
  event?: CalendarEvent | null;
  onClose: () => void;
}

/**
 * EventCreateModal Component
 * Create or edit calendar events
 * Simplified version matching TimeEntryCalendar aesthetic
 */
export function EventCreateModal({ dateKey, event, onClose }: EventCreateModalProps) {
  const { addEvent, updateEvent, events } = useCalendarStore();

  // Convert standard date key (YYYY-M-D) to ISO format for date input (YYYY-MM-DD)
  const toISODate = (standardKey: string): string => {
    const [year, month, day] = standardKey.split('-').map(Number);
    return `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
  };

  // Convert ISO date (YYYY-MM-DD) to standard date key (YYYY-M-D)
  const toStandardKey = (isoDate: string): string => {
    const [year, month, day] = isoDate.split('-').map(Number);
    return `${year}-${month}-${day}`;
  };

  // Form state
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState(toISODate(dateKey));
  const [isAllDay, setIsAllDay] = useState(true);
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('10:00');
  const [endDate, setEndDate] = useState('');
  const [location, setLocation] = useState('');
  const [reminders, setReminders] = useState<number[]>([]);
  const [recurrenceType, setRecurrenceType] = useState<'none' | 'daily' | 'weekly' | 'monthly' | 'yearly'>('none');
  const [weeklyDays, setWeeklyDays] = useState<number[]>([]);
  const [monthlyDay, setMonthlyDay] = useState(1);
  const [recurrenceEndType, setRecurrenceEndType] = useState<'never' | 'after' | 'until'>('never');
  const [recurrenceEndCount, setRecurrenceEndCount] = useState(10);
  const [recurrenceEndDate, setRecurrenceEndDate] = useState('');
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [conflicts, setConflicts] = useState<CalendarEvent[]>([]);

  // Initialize form when editing existing event
  useEffect(() => {
    if (event) {
      setTitle(event.title);
      setDescription(event.description || '');
      setStartDate(toISODate(dateKey));
      setIsAllDay(event.isAllDay !== false);
      setStartTime(event.startTime || '09:00');
      setEndTime(event.endTime || '10:00');
      setEndDate(event.endDate || '');
      setLocation(event.location || '');
      setReminders(event.reminders || []);

      if (event.recurrence) {
        setRecurrenceType(event.recurrence.frequency);
        setWeeklyDays(event.recurrence.daysOfWeek || []);
        setMonthlyDay(event.recurrence.dayOfMonth || 1);
        setRecurrenceEndType(event.recurrence.endType);
        setRecurrenceEndCount(event.recurrence.endCount || 10);
        setRecurrenceEndDate(event.recurrence.endDate || '');
      }
    }
  }, [event, dateKey]);

  // Check for conflicts when time changes
  useEffect(() => {
    // Skip conflict detection for all-day events
    if (isAllDay) {
      setConflicts([]);
      return;
    }

    // Get the standard date key from the ISO start date
    const effectiveDateKey = toStandardKey(startDate);

    // Get existing events for this date
    const existingEvents = events[effectiveDateKey] || [];

    // Detect conflicts
    const foundConflicts = detectConflicts(
      effectiveDateKey,
      startTime,
      endTime,
      existingEvents,
      event?.id // Exclude current event when editing
    );

    setConflicts(foundConflicts);
  }, [startDate, startTime, endTime, isAllDay, events, event]);

  const handleSave = async () => {
    setError('');

    // Validation
    if (!title.trim()) {
      setError('Event title is required');
      return;
    }

    if (!isAllDay && startTime >= endTime) {
      setError('End time must be after start time');
      return;
    }

    setSaving(true);
    try {
      const eventData: Partial<CalendarEvent> = {
        title: title.trim(),
        description: description.trim() || undefined,
        isAllDay,
        startTime: !isAllDay ? startTime : undefined,
        endTime: !isAllDay ? endTime : undefined,
        endDate: endDate || undefined,
        location: location.trim() || undefined,
        reminders: reminders.length > 0 ? reminders : undefined,
      };

      // Add recurrence if configured
      if (recurrenceType !== 'none' && !event) {
        eventData.recurrence = {
          frequency: recurrenceType,
          interval: 1,
          endType: recurrenceEndType,
          endCount: recurrenceEndType === 'after' ? recurrenceEndCount : undefined,
          endDate: recurrenceEndType === 'until' ? recurrenceEndDate : undefined,
        };

        if (recurrenceType === 'weekly' && weeklyDays.length > 0) {
          eventData.recurrence.daysOfWeek = weeklyDays;
        }

        if (recurrenceType === 'monthly') {
          eventData.recurrence.dayOfMonth = monthlyDay;
        }
      }

      // Get the standard date key from the ISO start date
      const effectiveDateKey = toStandardKey(startDate);

      if (event) {
        // Update existing event
        updateEvent(effectiveDateKey, event.id, eventData.title!, eventData.description, eventData);
      } else {
        // Create new event
        addEvent(effectiveDateKey, eventData.title!, eventData.description, eventData);
      }

      onClose();
    } catch (err) {
      console.error('Failed to save event:', err);
      setError('Failed to save event. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      onClose();
    } else if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
      handleSave();
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4"
      onClick={onClose}
    >
      <div
        className="bg-surface-light dark:bg-surface-dark rounded-button border border-border-light dark:border-border-dark shadow-xl max-w-lg w-full max-h-[90vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
        onKeyDown={handleKeyDown}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark sticky top-0 bg-surface-light dark:bg-surface-dark z-10">
          <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
            {event ? 'Edit Event' : 'Create Event'}
          </h2>
          <button
            onClick={onClose}
            className="p-1 rounded-button hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary transition-all duration-standard ease-smooth"
            aria-label="Close modal"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Body */}
        <div className="p-4 space-y-3">
          {error && (
            <div className="px-3 py-2 bg-status-error/10 border border-status-error/20 rounded-button text-status-error text-xs">
              {error}
            </div>
          )}

          {/* Conflict Warning */}
          {conflicts.length > 0 && (
            <div className="px-3 py-2 bg-status-warning/10 border border-status-warning/30 rounded">
              <div className="flex items-start gap-2">
                <AlertTriangle className="w-4 h-4 text-status-warning flex-shrink-0 mt-0.5" />
                <div className="flex-1">
                  <p className="text-xs font-medium text-status-warning mb-0.5">
                    {formatConflictMessage(conflicts)}
                  </p>
                  {conflicts.length <= 3 && (
                    <ul className="text-xs text-text-light-secondary dark:text-text-dark-secondary space-y-0.5">
                      {getConflictDetails(conflicts).map((detail, index) => (
                        <li key={index}>• {detail}</li>
                      ))}
                    </ul>
                  )}
                  <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-1">
                    You can still save this event, but consider adjusting the time to avoid overlaps.
                  </p>
                </div>
              </div>
            </div>
          )}

          {/* Start Date */}
          <div>
            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
              Date
            </label>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
          </div>

          {/* Title */}
          <div>
            <label
              htmlFor="event-title"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Event Title
            </label>
            <input
              id="event-title"
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
              placeholder="Meeting with team, Conference, etc."
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label
              htmlFor="event-description"
              className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5"
            >
              Description (Optional)
            </label>
            <textarea
              id="event-description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              rows={2}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary resize-none"
              placeholder="Add details about this event..."
            />
          </div>

          {/* All-Day Toggle */}
          <div>
            <label className="flex items-center gap-2 cursor-pointer">
              <input
                type="checkbox"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="rounded w-3.5 h-3.5"
              />
              <span className="text-xs text-text-light-primary dark:text-text-dark-primary">All-day event</span>
            </label>
          </div>

          {/* Time Inputs */}
          {!isAllDay && (
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  Start Time
                </label>
                <input
                  type="time"
                  value={startTime}
                  onChange={(e) => setStartTime(e.target.value)}
                  className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  End Time
                </label>
                <input
                  type="time"
                  value={endTime}
                  onChange={(e) => setEndTime(e.target.value)}
                  className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                />
              </div>
            </div>
          )}

          {/* End Date (Multi-day events) */}
          <div>
            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
              End Date (Optional - for multi-day events)
            </label>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              min={startDate}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
            />
            {endDate && (
              <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
                Event spans from {toStandardKey(startDate)} to {endDate}
              </p>
            )}
          </div>

          {/* Location */}
          <div>
            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
              Location (Optional)
            </label>
            <input
              type="text"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
              className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary"
              placeholder="Meeting room, video call link, address..."
            />
          </div>

          {/* Recurrence (only for new events) */}
          {!event && (
            <>
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                  Repeat
                </label>
                <select
                  value={recurrenceType}
                  onChange={(e) => setRecurrenceType(e.target.value as any)}
                  className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                >
                  <option value="none">Does not repeat</option>
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                  <option value="monthly">Monthly</option>
                </select>
              </div>

              {/* Weekly days selection */}
              {recurrenceType === 'weekly' && (
                <div>
                  <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                    Repeat on
                  </label>
                  <div className="grid grid-cols-7 gap-1.5">
                    {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map((day, index) => (
                      <button
                        key={index}
                        type="button"
                        onClick={() => {
                          if (weeklyDays.includes(index)) {
                            setWeeklyDays(weeklyDays.filter(d => d !== index));
                          } else {
                            setWeeklyDays([...weeklyDays, index].sort());
                          }
                        }}
                        className={`w-7 h-7 rounded-full text-xs font-medium transition-all ${
                          weeklyDays.includes(index)
                            ? 'bg-accent-magenta dark:bg-accent-cyan text-white'
                            : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-accent-magenta/20 dark:hover:bg-accent-cyan/20'
                        }`}
                      >
                        {day}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Monthly day selection */}
              {recurrenceType === 'monthly' && (
                <div>
                  <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                    Day of month
                  </label>
                  <input
                    type="number"
                    min="1"
                    max="31"
                    value={monthlyDay}
                    onChange={(e) => setMonthlyDay(Math.min(31, Math.max(1, parseInt(e.target.value) || 1)))}
                    className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                  />
                </div>
              )}

              {/* Recurrence end condition */}
              {recurrenceType !== 'none' && (
                <div>
                  <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
                    Ends
                  </label>
                  <select
                    value={recurrenceEndType}
                    onChange={(e) => setRecurrenceEndType(e.target.value as typeof recurrenceEndType)}
                    className="w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                  >
                    <option value="never">Never</option>
                    <option value="after">After</option>
                    <option value="until">On date</option>
                  </select>

                  {recurrenceEndType === 'after' && (
                    <div className="mt-1.5 flex items-center gap-2">
                      <input
                        type="number"
                        min="1"
                        max="999"
                        value={recurrenceEndCount}
                        onChange={(e) => setRecurrenceEndCount(Math.max(1, parseInt(e.target.value) || 1))}
                        className="w-16 px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                      />
                      <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                        occurrences
                      </span>
                    </div>
                  )}

                  {recurrenceEndType === 'until' && (
                    <input
                      type="date"
                      value={recurrenceEndDate}
                      onChange={(e) => setRecurrenceEndDate(e.target.value)}
                      className="mt-1.5 w-full px-2.5 py-1.5 text-xs bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button focus:outline-none focus:ring-2 focus:ring-accent-magenta dark:focus:ring-accent-cyan text-text-light-primary dark:text-text-dark-primary"
                    />
                  )}
                </div>
              )}
            </>
          )}

          {/* Reminders */}
          <div>
            <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1.5">
              Reminders (Optional)
            </label>
            <div className="space-y-1">
              {REMINDER_OPTIONS.map((option) => (
                <label key={option.value} className="flex items-center gap-2 text-xs cursor-pointer">
                  <input
                    type="checkbox"
                    checked={reminders.includes(option.value)}
                    onChange={(e) => {
                      if (e.target.checked) {
                        setReminders([...reminders, option.value].sort((a, b) => a - b));
                      } else {
                        setReminders(reminders.filter((r) => r !== option.value));
                      }
                    }}
                    className="rounded w-3.5 h-3.5"
                  />
                  <span className="text-text-light-secondary dark:text-text-dark-secondary">
                    {option.label}
                  </span>
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-2 px-4 py-3 border-t border-border-light dark:border-border-dark sticky bottom-0 bg-surface-light dark:bg-surface-dark">
          <button
            onClick={onClose}
            disabled={saving}
            className="px-3 py-1.5 text-xs font-medium text-text-light-primary dark:text-text-dark-primary bg-surface-light-elevated dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded-button hover:bg-surface-light dark:hover:bg-neutral-800 transition-all duration-standard ease-smooth disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            className="px-3 py-1.5 text-xs font-medium text-white dark:text-dark-background bg-accent-magenta dark:bg-accent-cyan rounded-button hover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {saving ? 'Saving...' : event ? 'Save Changes' : 'Create Event'}
          </button>
        </div>
      </div>
    </div>
  );
}

/**
 * Widget Settings Modal
 *
 * Clean modal interface for configuring widget settings
 * - Widget size (1x, 2x, 3x)
 * - Extensible for widget-specific settings
 */

import React, { useState } from 'react';
import { useWidgetStore } from '../stores/useWidgetStore';
import { getWidget } from '../widgets/Dashboard/WidgetRegistry';

interface WidgetSettingsModalProps {
  widgetId: string;
  isOpen: boolean;
  onClose: () => void;
}

export const WidgetSettingsModal: React.FC<WidgetSettingsModalProps> = ({
  widgetId,
  isOpen,
  onClose,
}) => {
  const widgetSizes = useWidgetStore((state) => state.widgetSizes);
  const setWidgetSize = useWidgetStore((state) => state.setWidgetSize);
  const currentSize = widgetSizes[widgetId] || 1;
  const [selectedSize, setSelectedSize] = useState<1 | 2 | 3>(currentSize);

  const widgetMeta = getWidget(widgetId);
  const isWeatherMap = widgetId === 'weathermap';

  const handleApply = () => {
    setWidgetSize(widgetId, selectedSize);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50"
        onClick={onClose}
      />

      {/* Modal */}
      <div className="fixed inset-0 flex items-center justify-center z-50 p-4">
        <div
          className="bg-white dark:bg-surface-dark-elevated rounded-button shadow-2xl border border-border-light dark:border-border-dark w-full max-w-md"
          onClick={(e) => e.stopPropagation()}
        >
          {/* Header */}
          <div className="flex items-center justify-between px-4 py-3 border-b border-border-light dark:border-border-dark">
            <h2 className="text-base font-semibold text-text-light-primary dark:text-text-dark-primary">
              Widget Settings
            </h2>
            <button
              onClick={onClose}
              className="p-1 hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button transition-all duration-standard ease-smooth"
              aria-label="Close"
            >
              <svg
                className="w-4 h-4 text-text-light-secondary dark:text-text-dark-secondary"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </button>
          </div>

          {/* Content */}
          <div className="px-4 py-4 space-y-4">
            {/* Widget Info */}
            <div>
              <h3 className="text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-0.5">
                {widgetMeta?.name || widgetId}
              </h3>
              <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary">
                {widgetMeta?.description || 'Configure widget settings'}
              </p>
            </div>

            {/* Size Selector */}
            {!isWeatherMap && (
              <div>
                <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
                  Widget Size
                </label>
                <div className="grid grid-cols-3 gap-2">
                  {([1, 2, 3] as const).map((size) => (
                    <button
                      key={size}
                      onClick={() => setSelectedSize(size)}
                      className={`
                        relative px-3 py-2 rounded-button border-2 transition-all duration-standard ease-smooth
                        ${selectedSize === size
                          ? 'border-accent-blue bg-accent-blue/10 dark:bg-accent-blue/20'
                          : 'border-border-light dark:border-border-dark hover:border-accent-blue/50'
                        }
                      `}
                    >
                      <div className="text-center">
                        <div className="text-base font-bold text-text-light-primary dark:text-text-dark-primary">
                          {size}x
                        </div>
                        <div className="text-[9px] text-text-light-secondary dark:text-text-dark-secondary mt-0.5">
                          {size === 1 ? 'Compact' : size === 2 ? 'Medium' : 'Wide'}
                        </div>
                      </div>
                      {selectedSize === size && (
                        <div className="absolute top-1.5 right-1.5 w-3.5 h-3.5 bg-accent-blue rounded-full flex items-center justify-center">
                          <svg
                            className="w-2.5 h-2.5 text-white"
                            fill="currentColor"
                            viewBox="0 0 20 20"
                          >
                            <path
                              fillRule="evenodd"
                              d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                              clipRule="evenodd"
                            />
                          </svg>
                        </div>
                      )}
                    </button>
                  ))}
                </div>
              </div>
            )}

            {isWeatherMap && (
              <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                Weather Map size is locked to ensure optimal display of the interactive map.
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="flex items-center justify-end gap-2 px-4 py-3 border-t border-border-light dark:border-border-dark">
            <button
              onClick={onClose}
              className="px-3 py-1.5 text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light-elevated dark:hover:bg-neutral-800 rounded-button transition-all duration-standard ease-smooth"
            >
              Cancel
            </button>
            <button
              onClick={handleApply}
              className="px-3 py-1.5 text-xs font-medium bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button transition-all duration-standard ease-smooth"
            >
              Apply
            </button>
          </div>
        </div>
      </div>
    </>
  );
};

